266	private func notificationHandler(contextObject: UnsafeMutableRawPointer?, sessionId: RimeSessionId, messageTypeC: UnsafePointer<CChar>?, messageValueC: UnsafePointer<CChar>?) {
267	  let delegate: SquirrelApplicationDelegate = Unmanaged<SquirrelApplicationDelegate>.fromOpaque(contextObject!).takeUnretainedValue()
268	
269	  let messageType = messageTypeC.map { String(cString: $0) }
270	  let messageValue = messageValueC.map { String(cString: $0) }
271	
272	  if messageType == "deploy" {
273	    switch messageValue {
274	    case "start":
275	      SquirrelApplicationDelegate.showMessage(msgText: NSLocalizedString("deploy_start", comment: ""))
276	    case "success":
277	      SquirrelApplicationDelegate.showMessage(msgText: NSLocalizedString("deploy_success", comment: ""))
278	    case "failure":
279	      SquirrelApplicationDelegate.showMessage(msgText: NSLocalizedString("deploy_failure", comment: ""))
280	    default:
281	      break
282	    }
283	    return
284	  } else if messageType == "option" {
285	    let state = messageValue?.first != "!"
286	    let optionName: String?
287	    if state {
288	      optionName = messageValue
289	    } else if let value = messageValue {
290	      optionName = String(value[value.index(after: value.startIndex)...])
291	    } else {
292	      optionName = nil
293	    }
294	    if let optionName = optionName {
295	      optionName.withCString { name in
296	        func shortLabel() -> String? {
297	          let stateLabelShort = delegate.rimeAPI.get_state_label_abbreviated(sessionId, name, state, true)
298	          return stateLabelShort.asString
299	        }
300	        func longLabel() -> String? {
301	          let stateLabelLong = delegate.rimeAPI.get_state_label_abbreviated(sessionId, name, state, false)
302	          return stateLabelLong.asString
303	        }
304	        if optionName == "ascii_mode" {
305	          delegate.updateStatusIcon(asciiMode: state, schemaLabel: shortLabel())
306	        }
307	        if delegate.enableNotifications {
308	          delegate.showStatusMessage(msgTextLong: longLabel(), msgTextShort: shortLabel())
309	        }
310	      }
311	    }
312	    return
313	  } else if messageType == "property", let messageValue = messageValue,
314	            let eqIndex = messageValue.firstIndex(of: "="), messageValue.first == "_" {
315	    let key = String(messageValue[..<eqIndex])
316	    let value = String(messageValue[messageValue.index(after: eqIndex)...])
317	    Task.detached { @MainActor in
318	      do {
319	        try delegate.panel?.inputController?.handleReservedProperty(key: key, value: value, for: sessionId)
320	      } catch {
321	        print("Error processing handleReservedProperty: \(error)")
322	      }
323	    }
324	    return
325	  }
326	
327	  if delegate.enableNotifications {
328	    if messageType == "schema", let messageValue = messageValue, let schemaName = try? /^[^\/]*\/(.*)$/.firstMatch(in: messageValue)?.output.1 {
329	      delegate.showStatusMessage(msgTextLong: String(schemaName), msgTextShort: String(schemaName))
330	      return
331	    }
332	  }
333	}
